      const originalTransactionPair = transactionPairs?.[0];
      const originalRequest = originalTransactionPair?.request;

      if (actionPageId) {
        const currentUpgrade = getCurrentUpgrade(originalRequest);
        const numberOfPages = (currentUpgrade?.actionPageIds || []).length;
        if (numberOfPages > 1) {
          const dismissedUpgrades = dismissUpgrade(actionPageId);

          if (dismissedUpgrades.length < numberOfPages) {
            return;
