        } else if (frequency === SourceFrequency.Quarterly) {
          multiplier = 4;
        } else if (frequency === SourceFrequency.Daily) {
          multiplier = 365;
        }

        await logSuccessfulSubmission({
          city,
          country,
          email: rest.email,
          firstName: rest.firstName,
          frequency: frequency as SourceFrequency,
          lastName: rest.lastName,
          postalCode,
          predictedLtv: multiplier * totalAmount,
          region,
          submissionId: id,
          transactionTotal: currency(totalAmount, { fromCents: true }).value ?? 0,
        });
      } finally {
        // Post message if we are in an iframe
        if (window.location !== window.parent.location) {
          window.parent.postMessage(response, '*');
        }

        // allows future pledge to short circuit
        if (!useUpgradeWorkflow) {
          if (showReceiptIfSkippingUpgrades) {
            showReceipt(response);
          }

          return;
        }
        const currentUpgrade = getCurrentUpgrade(originalSubmission);
        const numberOfPages = (currentUpgrade?.actionPageIds || []).length;

        if (numberOfPages > 1) {
          const dismissedUpgrades = dismissUpgrade(request.actionPageId!);

          if (dismissedUpgrades.length < numberOfPages) {
            return;
          }
        }

        if (shouldActivateUpgrade && !isEvent) {
          activateNextUpgrade(originalSubmission);
        } else {
          if (callbackUrl) {
            if (isEmbedded && window.top) {
              window.top.location.href = callbackUrl;
            } else {
              window.location.replace(callbackUrl);
            }
          } else {
            showReceipt(response);
          }
        }
      }
    },
    [
      activateNextUpgrade,
      dismissUpgrade,
      getCurrentUpgrade,
      hasNextUpgrade,
      isEmbedded,
      isEvent,
      logSuccessfulSubmission,
      showReceipt,
      transactionPairs,
    ]
  );

  const submitActionPageForm = useCallback(
    async (submission: ActionPageSubmissionForm, form?: UseFormReturn) => {
      const {
        accountHolderType,
        accountNumber,
        accountType,
        aceProductSelectionsAttributes,
        actionPageId,
        addressAttributes = {},
        amountAllocationsAttributes,
        cardZip,
        communicationsConsentEmail,
        communicationsConsentPhone,
        customFieldPositionsAttributes,
        customFieldResponsesAttributes,
        cvv,
        eventTicketsAttributes,
        expDate,
        expressCheckoutMethod,
        frequency: selectedFrequency,
        futurePledgeDate,
        futurePledgeSelected: formFuturePledgeSelection,
        hasValidUpgradePaymentMethod,
        makeDonationAs,
        organization,
        organizationType,
        pageType,
        plaidBankAccountId,
        promoCodeAttributes,
        referrer,
        routingNumber,
        storefrontProductSelectionsAttributes,
        type,
        vaultToken,
        ...rest
      } = submission;

      const isStorefront = pageType === 'storefront';
      let submissionPaymentMethodAttributes = {};
      // OpenNode is one time only, no future pledge
      const frequency = type !== 'bitcoin_open_node' ? selectedFrequency : null;
      const futurePledgeSelected = type !== 'bitcoin_open_node' ? formFuturePledgeSelection : false;
      const futurePledgeCaptureAt = futurePledgeDate ? parseISO(futurePledgeDate) : null;

      const futurePledgeValid =
        !isStorefront &&
        futurePledgeSelected &&
        futurePledgeCaptureAt &&
        isAfter(futurePledgeCaptureAt, new Date());

      const scheduleAttributes: Partial<CommitmentSchedule> | undefined =
        frequencyToCommitmentSchedule(frequency) ||
        (futurePledgeValid
          ? {
              every: 'once',
              interval: 1,
              starts: futurePledgeDate,
              until: futurePledgeDate,
            }
          : undefined);

      if (isDonationPage(pageType)) {
        // Check open node first, then fall into saved payment methods for the donor profile
        if (type === 'bitcoin_open_node') {
          submissionPaymentMethodAttributes = {
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            type: SubmissionPaymentMethods.OpenNode,
          };
        } else if (type === 'applepay') {
          submissionPaymentMethodAttributes = {
            ...rest.submissionPaymentMethodAttributes,
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            type: 'SubmissionPaymentMethods::Applepay',
          };
        } else if (type === 'googlepay') {
          submissionPaymentMethodAttributes = {
            ...rest.submissionPaymentMethodAttributes,
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            type: 'SubmissionPaymentMethods::Googlepay',
          };
        } else if (rest.hasValidDonorPaymentMethod && !!rest.paymentMethodId) {
          submissionPaymentMethodAttributes = {
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            paymentMethodId: rest.paymentMethodId,
            type:
              type === 'paypal'
                ? 'SubmissionPaymentMethods::Paypal'
                : 'SubmissionPaymentMethods::Saved',
          };
        } else if (type === 'paypal') {
          submissionPaymentMethodAttributes = {
            ...rest.submissionPaymentMethodAttributes,
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            type: 'SubmissionPaymentMethods::Paypal',
          };
        } else if (type === 'credit_card') {
          if (expDate && vaultToken) {
            const { cardMonth, cardYear } = splitExpDate(expDate!);
            const encryptedCardNumber = encrypt(vaultToken!);
            submissionPaymentMethodAttributes = {
              cardCode: cvv!,
              cardMonth,
              cardYear,
              cardZip,
              customerCoveredFees: submission.customerCoveredFees,
              encryptedCardNumber,
              type: 'SubmissionPaymentMethods::CreditCard',
            };
          }
        } else if (type === 'bank_account') {
          submissionPaymentMethodAttributes = {
            accountHolderType,
            accountNumber,
            accountType,
            customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
            routingNumber,
            type: 'SubmissionPaymentMethods::BankAccount',
          };
        } else if (type === 'plaid_bank_account') {
          if (plaidBankAccountId) {
            submissionPaymentMethodAttributes = {
              accountHolderType,
              customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
              plaidBankAccountId,
              type: 'SubmissionPaymentMethods::Plaid',
            };
          } else {
            submissionPaymentMethodAttributes = {
              accountHolderType,
              accountNumber,
              accountType,
              customerCoveredFees: isStorefront ? true : submission.customerCoveredFees,
              routingNumber,
              type: 'SubmissionPaymentMethods::BankAccount',
            };
          }
        }
      }

      // Remove superfluous attributes
      // @ts-ignore
      delete rest.csrfToken;
      delete rest.customerCoveredFees;
      delete rest.isUpdatingMethod;
      delete rest.otherAmount;
      // @ts-ignore
      delete rest.donorProfile;
      delete rest.hasValidDonorPaymentMethod;
      // @ts-ignore
      delete rest.cardType;
      delete rest.confirmNumber;
      delete rest.paymentMethodId;
      delete rest.name;
      delete rest.employed;
      delete rest.hideExpressCheckoutControls;
      delete rest.isInUpgradeChain;

      const newCustomFieldResponsesAttributes = serializeCustomFieldResponses(
        customFieldResponsesAttributes ?? {},
        customFieldPositionsAttributes
      );

      // Promo codes: apply the discount proportionately across all funds, but only to ticket amounts
      const promoCodeDiscount = rest.promoCodeDiscount || 0;
      const ticketTotalAmount =
        eventTicketsAttributes
          ?.map(({ ticketTypeId }: { ticketTypeId: string }) => {
            const price = actionPage?.event?.ticketTypes?.find(
              (ticket) => ticket.id === ticketTypeId
            )?.price;

            return price ?? 0;
          })
          .reduce((acc: number, curr: number) => acc + curr, 0) ?? 0;
      const ticketTotalAmountAfterDiscount = Math.max(ticketTotalAmount - promoCodeDiscount);
      const donationAmount = amountAllocationsAttributes
        ? amountAllocationsAttributes.reduce((sum, fund) => sum + (fund.amount || 0), 0)
        : 0;
      const totalAmount = donationAmount + ticketTotalAmountAfterDiscount;
      const funds = actionPage.fundConfiguration?.fundSelectionsAttributes;

      const submissionAmountAllocationsAttributes = (
        totalAmount === 0
          ? []
          : ticketTotalAmountAfterDiscount === 0
            ? amountAllocationsAttributes
            : donationAmount === 0 && ticketTotalAmountAfterDiscount > 0
              ? // Populate amountAllocations with ticket total
                (funds ?? [])
                  .filter((fund) => fund.shown || fund.shown === null)
                  .map((fund) => {
                    const { percentage, type: fundType } = fund;
                    const allocationAmount = Math.round(
                      ((percentage ?? 0 / 100) * ticketTotalAmountAfterDiscount) / 100
                    );

                    return {
                      actionPagesFundId: fund.fund.id,
                      amount: allocationAmount,
                      fundType: fundType === 'direct' ? null : fundType,
                    };
                  })
              : // Add ticket total after discount proportionally to amountAllocations
                (amountAllocationsAttributes ?? []).map((allocation) => {
                  const allocationAmount = allocation.amount || 0;
                  // Calculate the allocation's `percentage` based on the total `donationAmount`.
                  // We can't rely on the associated fund's `percentage` here, because the user
                  // may be able to modify the fund allocation, which means the configured
                  // fund split `percentage` may no longer apply.
                  const allocationPercentage = allocationAmount / donationAmount;
                  const proportionalTicketAmount = Math.round(
                    allocationPercentage * ticketTotalAmountAfterDiscount
                  );

                  return {
                    ...allocation,
                    amount: proportionalTicketAmount + allocationAmount,
                    fundType: allocation.fundType === 'direct' ? null : allocation.fundType,
                  };
                })
      )?.filter((allocation) => allocation.amount > 0);

      delete rest.promoCodeDiscount;

      const submissionInner = {
        ...rest,
        aceProductSelectionsAttributes,
        addressAttributes,
        communicationsConsentEmail: !actionPage.fieldConfiguration.displayCommunicationsConsent
          ? null
          : communicationsConsentEmail,
        communicationsConsentPhone: !actionPage.fieldConfiguration.displayCommunicationsConsent
          ? null
          : communicationsConsentPhone,
        currentlyEmployed:
          // Turns out the radio control populates string values instead of boolean
          // @ts-ignore
          submission.employed === 'false'
            ? false
            : // Turns out the radio control populates string values instead of boolean
              // @ts-ignore
              submission.employed === 'true'
              ? true
              : submission.employed,
        customFieldResponsesAttributes: newCustomFieldResponsesAttributes,
        organization: makeDonationAs !== 'individual' ? organization : undefined,
        organizationType: makeDonationAs !== 'individual' ? organizationType : undefined,
        referrer: referrer || window.location.href,
        rumbleUpRequestId,
        savePaymentMethod: type !== 'bitcoin_open_node' ? rest.savePaymentMethod : false,
        storefrontProductSelectionsAttributes,
        // Use account number for pro accounts on restricted pages
        ...(proEnabled && isRestricted && !rest.phone ? { phone: actionPage.account.phone } : {}),
      };

      const submissionType =
        (isEvent && !eventTicketsAttributes) ||
        (actionPage.pageType === 'lead' && (submissionAmountAllocationsAttributes?.length ?? 0) > 0)
          ? 'donation'
          : actionPage.pageType;

      const actionPageSubmission = {
        submission: {
          ...submissionInner,
          amountAllocationsAttributes: submissionAmountAllocationsAttributes,
          ddcSessionId,
          scheduleAttributes,
          submissionPaymentMethodAttributes,
        },
        type: submissionType,
      } as ActionPageSubmissionRequest;

      const onError = (response: IErrorResponse) => {
        const message = formatSubmissionErrorMessage(
          response as { response?: { status: number } },
          t
        );

        showToast({
          message,
          variant: 'error',
        });

        resetTurnstile();

        form?.trigger();

        const e = {
          cause: response,
          message: 'Unable to complete submission',
          name: 'SubmissionError',
        };

        console.error(e);
        rollbar.error(e);
      };

      const onSuccess = async (response: PublicSubmission) => {
        // hide express checkout controls through the chain if necessary
        // If they used express checkout, we should show the controls on the
        // next upgrade
        trackSubmission(
          {
            ...submission,
            actionPageId,
            hasValidUpgradePaymentMethod:
              hasValidUpgradePaymentMethod || isDonationPage(submission.pageType),
            hideExpressCheckoutControls:
              submission.hideExpressCheckoutControls ||
              (submission.type !== 'lead' && !expressCheckoutMethod) ||
              expressCheckoutMethod === 'googlepay',
            submissionPaymentMethodAttributes:
              actionPageSubmission.submission.submissionPaymentMethodAttributes,
